module RefModule(
    // ports
    output wire out,
    input wire in1,
    input wire in2,
    input wire en
);// internal signals
    wire mux_output;

    // 2-to-1 multiplexer
    wire __mux_output_tmp = (en == 1'b0) ? in1 : in2;
    assign mux_output = __mux_output_tmp;

    // output
    assign out = mux_output;

endmodule
